/// @brief Common test encoding entry (matches all ISA test_encodings.h).
struct TestEncEntry {
  std::string_view mnemonic;
  std::array<uint32_t, 2> words;
};

constexpr uint32_t pack16(uint16_t lo, uint16_t hi) {
  return static_cast<uint32_t>(lo) | (static_cast<uint32_t>(hi) << 16);
}

constexpr std::array<uint32_t, 2> encode_vop3(uint32_t op, uint32_t vdst, uint32_t src0,
                                              uint32_t src1, uint32_t src2, uint32_t abs = 0,
                                              uint32_t opsel = 0, uint32_t clamp = 0,
                                              uint32_t omod = 0, uint32_t neg = 0) {
  return {vdst | ((abs & 0x7u) << 8) | ((opsel & 0xFu) << 11) | ((clamp & 0x1u) << 15) |
              ((op & 0x3FFu) << 16) | (0x35u << 26),
          (src0 & 0x1FFu) | ((src1 & 0x1FFu) << 9) | ((src2 & 0x1FFu) << 18) |
              ((omod & 0x3u) << 27) | ((neg & 0x7u) << 29)};
}

constexpr std::array<uint32_t, 2> encode_vop2(uint32_t op, uint32_t vdst, uint32_t src0,
                                              uint32_t vsrc1) {
  return {(src0 & 0x1FFu) | ((vsrc1 & 0xFFu) << 9) | ((vdst & 0xFFu) << 17) | ((op & 0x3Fu) << 25),
          0u};
}

constexpr std::array<uint32_t, 2> encode_sop1(uint32_t op, uint32_t sdst, uint32_t ssrc0) {
  return {(ssrc0 & 0xFFu) | ((op & 0xFFu) << 8) | ((sdst & 0x7Fu) << 16) | 0xBE800000u, 0u};
}

constexpr std::array<uint32_t, 2> encode_sop2(uint32_t op, uint32_t sdst, uint32_t ssrc0,
                                              uint32_t ssrc1) {
  return {(ssrc0 & 0xFFu) | ((ssrc1 & 0xFFu) << 8) | ((sdst & 0x7Fu) << 16) | ((op & 0x7Fu) << 23) |
              (0x2u << 30),
          0u};
}

class Gfx1250MemoryTestCu
    : public amdgpu::IsaExecComputeUnit<simdojo::ExecMode::FUNCTIONAL, gfx1250::Isa> {
public:
  using Base = amdgpu::IsaExecComputeUnit<simdojo::ExecMode::FUNCTIONAL, gfx1250::Isa>;

  Gfx1250MemoryTestCu(std::string name, const amdgpu::ComputeUnitCore::Config &config,
                      amdgpu::GpuMemory *memory, amdgpu::L2Cache *l2)
      : Base(std::move(name), config, memory, l2) {
    if (l2)
      l2->set_backing_memory(memory);
    set_memory(memory);
    set_l2(l2);
  }

  void execute_and_route(Instruction *inst, amdgpu::Wavefront &wf) {
    execute_instruction(inst, wf);
    if (inst->is_memory_op())
      route_memory_inst(inst, wf);
    else
      delete inst;
  }
};

/// @brief Check if a mnemonic should be skipped in the execution harness.
///
/// Memory instructions require valid addresses and will crash on zeroed state.
/// Control flow instructions (branch, endpgm, barrier, waitcnt, trap) may
/// halt, loop, or enter wait states that hang the test.
inline bool should_skip_inst(std::string_view mn) {
  // Only execute scalar ALU instructions (s_* that don't touch memory or
  // control flow). Vector instructions may crash because the synthesized
  // encoding has src0=0 which maps to SGPR[0] for scalar source, but in
  // VOP encodings src0=0 is VGPR[0] and VGPR reading with zeroed register
  // allocation can segfault.
  //
  // Allowlist approach: only s_* instructions that are pure ALU.
  if (mn.empty() || mn[0] != 's' || mn[1] != '_')
    return true; // Skip all non-scalar instructions.
  static constexpr std::string_view SKIP_PREFIXES[] = {
      // Memory instructions
      "s_load_",
      "s_store_",
      "s_buffer_",
      "s_dcache_",
      "s_atomic_",
      // Control flow that halts or waits
      "s_endpgm",
      "s_branch",
      "s_cbranch",
      "s_setpc",
      "s_swappc",
      "s_call",
      "s_waitcnt",
      "s_wait_",
      "s_barrier",
      "s_trap",
      "s_sleep",
      "s_sethalt",
      "s_sendmsg",
      "s_sendmsghalt",
      "s_icache_inv",
      "s_nop",
      "s_getpc",
      "s_getreg",
      "s_setreg",
      "s_rfe",
  };
  for (auto p : SKIP_PREFIXES)
    if (mn.substr(0, p.size()) == p)
      return true;
  return false;
}

/// @brief Helper to run all test encodings for a given ISA.
void run_execution_harness(rj_code_arch_t arch, std::string_view arch_name,
                           const TestEncEntry *encodings, size_t num_encodings) {
  // Set up minimal CU with zeroed memory.
  amdgpu::GpuMemory gpu_mem(std::string(arch_name) + "_mem");
  amdgpu::L2Cache l2(std::string(arch_name) + "_l2");

  amdgpu::ComputeUnitCore::Config cfg{};
  cfg.arch = arch;
  cfg.num_wf_slots = 1;
  cfg.sgprs_per_wf = 106; // max across all ISAs
  cfg.vgprs_per_wf = 256;
  cfg.lds_size_kb = 64;

  auto cu = amdgpu::ComputeUnitCore::create(std::string(arch_name), cfg, &gpu_mem, &l2);
  ASSERT_NE(cu, nullptr) << "Failed to create CU for " << arch_name;

  auto decoder = Decoder::create(arch);
  ASSERT_NE(decoder, nullptr) << "Failed to create decoder for " << arch_name;

  size_t total = num_encodings;
  [[maybe_unused]] size_t decoded = 0;
  size_t executed = 0;
  size_t unimplemented = 0;
  size_t skipped_mem = 0;
  std::vector<std::string> unimpl_list;
  std::vector<std::string> decode_fail_list;

  for (size_t i = 0; i < total; ++i) {
    const auto &te = encodings[i];

    // Skip memory instructions — they require valid addresses and will
    // crash or hang when executed on zeroed wavefront/memory state.
    if (should_skip_inst(te.mnemonic)) {
      ++skipped_mem;
      continue;
    }

    // Decode the instruction.
    std::unique_ptr<Instruction> inst;
    try {
      inst.reset(decoder->decode(te.words.data()));
    } catch (const util::InvalidInst &) {
      decode_fail_list.emplace_back(te.mnemonic);
      continue;
    } catch (...) {
      decode_fail_list.emplace_back(te.mnemonic);
      continue;
    }
    if (!inst) {
      decode_fail_list.emplace_back(te.mnemonic);
      continue;
    }
    ++decoded;

    // Dispatch a fresh wavefront for each instruction to avoid state leaks.
    amdgpu::Wavefront *wf = cu->dispatch_wf(0, 0, cfg.sgprs_per_wf, cfg.vgprs_per_wf);
    if (!wf) {
      // Reset the slot and try again.
      cu->reset_all_wf();
      wf = cu->dispatch_wf(0, 0, cfg.sgprs_per_wf, cfg.vgprs_per_wf);
    }
    ASSERT_NE(wf, nullptr) << "Failed to dispatch WF for " << te.mnemonic;

    // Execute and catch UnimplementedInst.
    try {
      cu->execute_instruction(inst.get(), *wf);
      ++executed;
    } catch (const util::UnimplementedInst &) {
      ++unimplemented;
      unimpl_list.emplace_back(te.mnemonic);
    } catch (...) {
      ++executed; // Other exceptions are acceptable on zeroed state.
    }

    // Reset the wavefront for the next instruction.
    cu->reset_all_wf();
  }

  size_t testable = total - skipped_mem;
  double coverage = testable > 0 ? 100.0 * executed / testable : 0.0;
  std::printf(
      "\n  %.*s: %zu/%zu executed (%.1f%%), %zu unimplemented, %zu decode fail, %zu mem skipped\n",
      static_cast<int>(arch_name.size()), arch_name.data(), executed, testable, coverage,
      unimplemented, decode_fail_list.size(), skipped_mem);

  if (!unimpl_list.empty()) {
    std::printf("  Unimplemented (%zu):", unimpl_list.size());
    for (size_t i = 0; i < std::min(unimpl_list.size(), size_t{20}); ++i)
      std::printf(" %s", unimpl_list[i].c_str());
    if (unimpl_list.size() > 20)
      std::printf(" ... +%zu more", unimpl_list.size() - 20);
    std::printf("\n");
  }

  // Decode failures are expected for sub-decoded encodings where the
  // synthesized test word doesn't match the decoder's sub-dispatch path.
  // The primary coverage metric is: of the instructions that DO decode,
  // how many execute without throwing UnimplementedInst?
  // Unimplemented instructions are tracked in coverage_exceptions files.
  EXPECT_GT(decoded, 0u) << "No instructions decoded for " << arch_name;
}

// --- Parameterized tests per ISA ---

// Helper macro: cast the ISA-specific TestEncoding array to the common layout.
// The struct layout (string_view + array<uint32_t,2>) is identical across all ISAs.
#define RUN_HARNESS(ISA_NS, ARCH_ENUM, ARCH_STR)                                                   \
  run_execution_harness(ARCH_ENUM, ARCH_STR,                                                       \
                        reinterpret_cast<const TestEncEntry *>(ISA_NS::test_data::ENCODINGS),      \
                        ISA_NS::test_data::NUM_ENCODINGS)

TEST(InstructionExecutionHarness, Cdna1) { RUN_HARNESS(cdna1, ROCJITSU_CODE_ARCH_CDNA1, "cdna1"); }
TEST(InstructionExecutionHarness, Cdna2) { RUN_HARNESS(cdna2, ROCJITSU_CODE_ARCH_CDNA2, "cdna2"); }
TEST(InstructionExecutionHarness, Cdna3) { RUN_HARNESS(cdna3, ROCJITSU_CODE_ARCH_CDNA3, "cdna3"); }
TEST(InstructionExecutionHarness, Cdna4) { RUN_HARNESS(cdna4, ROCJITSU_CODE_ARCH_CDNA4, "cdna4"); }
TEST(InstructionExecutionHarness, Rdna1) { RUN_HARNESS(rdna1, ROCJITSU_CODE_ARCH_RDNA1, "rdna1"); }
TEST(InstructionExecutionHarness, Rdna2) { RUN_HARNESS(rdna2, ROCJITSU_CODE_ARCH_RDNA2, "rdna2"); }
TEST(InstructionExecutionHarness, Rdna3) { RUN_HARNESS(rdna3, ROCJITSU_CODE_ARCH_RDNA3, "rdna3"); }
TEST(InstructionExecutionHarness, Rdna3_5) {
  RUN_HARNESS(rdna3_5, ROCJITSU_CODE_ARCH_RDNA3_5, "rdna3_5");
}
TEST(InstructionExecutionHarness, Rdna4) { RUN_HARNESS(rdna4, ROCJITSU_CODE_ARCH_RDNA4, "rdna4"); }
