TEST(Rdna4ScalarSccTest, AddSubCoI32UseSignedOverflow) {
  amdgpu::GpuMemory gpu_mem("rdna4_scc_i32_overflow_mem");
  amdgpu::L2Cache l2("rdna4_scc_i32_overflow_l2");

  amdgpu::ComputeUnitCore::Config cfg{};
  cfg.arch = ROCJITSU_CODE_ARCH_RDNA4;
  cfg.num_wf_slots = 1;
  cfg.sgprs_per_wf = 106;
  cfg.vgprs_per_wf = 256;
  cfg.lds_size_kb = 64;

  auto cu = amdgpu::ComputeUnitCore::create("rdna4", cfg, &gpu_mem, &l2);
  ASSERT_NE(cu, nullptr);

  auto decoder = Decoder::create(ROCJITSU_CODE_ARCH_RDNA4);
  ASSERT_NE(decoder, nullptr);

  auto *wf = cu->dispatch_wf(0, 0, cfg.sgprs_per_wf, cfg.vgprs_per_wf);
  ASSERT_NE(wf, nullptr);

  const uint32_t sb = wf->sgpr_alloc().base;
  auto run = [&](const std::array<uint32_t, 2> &words, std::string_view mnemonic, uint32_t lhs,
                 uint32_t rhs, uint32_t expected_result, bool expected_scc) {
    std::unique_ptr<Instruction> inst(decoder->decode(words.data()));
    ASSERT_NE(inst, nullptr);
    ASSERT_EQ(std::string_view(inst->mnemonic()), mnemonic);

    cu->write_sgpr(sb + 0, lhs);
    cu->write_sgpr(sb + 1, rhs);
    wf->write_scc(!expected_scc);
    cu->execute_instruction(inst.get(), *wf);

    EXPECT_EQ(cu->read_sgpr(sb + 2), expected_result) << mnemonic;
    EXPECT_EQ(wf->read_scc(), expected_scc) << mnemonic;
  };

  const auto add = encode_sop2(/*op=*/2, /*sdst=*/2, /*ssrc0=*/0, /*ssrc1=*/1);
  const auto sub = encode_sop2(/*op=*/3, /*sdst=*/2, /*ssrc0=*/0, /*ssrc1=*/1);

  run(add, "s_add_co_i32", 0x7FFFFFFFu, 1u, 0x80000000u, true);
  run(add, "s_add_co_i32", 0x7FFFFFFFu, 0u, 0x7FFFFFFFu, false);
  run(sub, "s_sub_co_i32", 0x80000000u, 1u, 0x7FFFFFFFu, true);
  run(sub, "s_sub_co_i32", 5u, 3u, 2u, false);

  cu->reset_all_wf();
}

struct ScalarCvtSccCase {
  uint32_t op;
  const char *mnemonic;
  uint32_t src;
  uint32_t expected;
};

void run_scalar_cvt_preserves_scc(rj_code_arch_t arch, std::string_view arch_name,
                                  const ScalarCvtSccCase *cases, size_t num_cases) {
  amdgpu::GpuMemory gpu_mem(std::string(arch_name) + "_s_cvt_scc_mem");
  amdgpu::L2Cache l2(std::string(arch_name) + "_s_cvt_scc_l2");

  amdgpu::ComputeUnitCore::Config cfg{};
  cfg.arch = arch;
  cfg.num_wf_slots = 1;
  cfg.sgprs_per_wf = 106;
  cfg.vgprs_per_wf = 256;
  cfg.lds_size_kb = 64;

  auto cu = amdgpu::ComputeUnitCore::create(std::string(arch_name), cfg, &gpu_mem, &l2);
  ASSERT_NE(cu, nullptr) << arch_name;

  auto decoder = Decoder::create(arch);
  ASSERT_NE(decoder, nullptr) << arch_name;

  auto *wf = cu->dispatch_wf(0, 0, cfg.sgprs_per_wf, cfg.vgprs_per_wf);
  ASSERT_NE(wf, nullptr) << arch_name;

  const uint32_t sb = wf->sgpr_alloc().base;

  for (size_t i = 0; i < num_cases; ++i) {
    const auto &tc = cases[i];
    const auto words = encode_sop1(tc.op, /*sdst=*/1, /*ssrc0=*/0);
    for (bool initial_scc : std::array<bool, 2>{false, true}) {
      std::unique_ptr<Instruction> inst(decoder->decode(words.data()));
      ASSERT_NE(inst, nullptr);
      ASSERT_EQ(std::string_view(inst->mnemonic()), tc.mnemonic) << arch_name;

      cu->write_sgpr(sb + 0, tc.src);
      cu->write_sgpr(sb + 1, 0u);
      wf->write_scc(initial_scc);
      cu->execute_instruction(inst.get(), *wf);

      EXPECT_EQ(cu->read_sgpr(sb + 1), tc.expected) << arch_name << " " << tc.mnemonic;
      EXPECT_EQ(wf->read_scc(), initial_scc)
          << arch_name << " " << tc.mnemonic << " initial_scc=" << initial_scc;
    }
  }

  cu->reset_all_wf();
}

TEST(ScalarSccTest, ScalarCvtPreservesScc) {
  const uint32_t one_f32 = std::bit_cast<uint32_t>(1.0f);
  const uint32_t one_f16 = util::f32_to_f16(1.0f);
  const uint32_t qnan_f32 = 0x7FC00000u;
  const uint32_t i32_overflow_f32 = std::bit_cast<uint32_t>(2147483648.0f);
  const uint32_t below_i32_min_f32 = std::bit_cast<uint32_t>(-2147483904.0f);
  const uint32_t u32_overflow_f32 = std::bit_cast<uint32_t>(4294967296.0f);

  const std::array<ScalarCvtSccCase, 13> cases{{
      {0x64u, "s_cvt_f32_i32", 1u, one_f32},
      {0x65u, "s_cvt_f32_u32", 1u, one_f32},
      {0x66u, "s_cvt_i32_f32", one_f32, 1u},
      {0x66u, "s_cvt_i32_f32", qnan_f32, 0u},
      {0x66u, "s_cvt_i32_f32", i32_overflow_f32, 0x7FFFFFFFu},
      {0x66u, "s_cvt_i32_f32", below_i32_min_f32, 0x80000000u},
      {0x67u, "s_cvt_u32_f32", one_f32, 1u},
      {0x67u, "s_cvt_u32_f32", qnan_f32, 0u},
      {0x67u, "s_cvt_u32_f32", std::bit_cast<uint32_t>(-1.0f), 0u},
      {0x67u, "s_cvt_u32_f32", u32_overflow_f32, 0xFFFFFFFFu},
      {0x68u, "s_cvt_f16_f32", one_f32, one_f16},
      {0x69u, "s_cvt_f32_f16", one_f16, one_f32},
      {0x6Au, "s_cvt_hi_f32_f16", one_f16 << 16, one_f32},
  }};

  run_scalar_cvt_preserves_scc(ROCJITSU_CODE_ARCH_RDNA3_5, "rdna3_5", cases.data(), cases.size());
  run_scalar_cvt_preserves_scc(ROCJITSU_CODE_ARCH_RDNA4, "rdna4", cases.data(), cases.size());
  run_scalar_cvt_preserves_scc(ROCJITSU_CODE_ARCH_GFX1250, "gfx1250", cases.data(), cases.size());
}

TEST(Rdna3Dot2ExecutionTest, Vop2Dot2accF32F16AccumulatesDst) {
  amdgpu::GpuMemory gpu_mem("rdna3_dot2acc_vop2_mem");
  amdgpu::L2Cache l2("rdna3_dot2acc_vop2_l2");

  amdgpu::ComputeUnitCore::Config cfg{};
  cfg.arch = ROCJITSU_CODE_ARCH_RDNA3;
  cfg.num_wf_slots = 1;
  cfg.sgprs_per_wf = 106;
  cfg.vgprs_per_wf = 256;
  cfg.lds_size_kb = 64;

  auto cu = amdgpu::ComputeUnitCore::create("rdna3", cfg, &gpu_mem, &l2);
  ASSERT_NE(cu, nullptr);

  auto decoder = Decoder::create(ROCJITSU_CODE_ARCH_RDNA3);
  ASSERT_NE(decoder, nullptr);

  auto *wf = cu->dispatch_wf(0, 0, cfg.sgprs_per_wf, cfg.vgprs_per_wf);
  ASSERT_NE(wf, nullptr);
  wf->set_exec(0x1u);

  const uint32_t vb = wf->vgpr_alloc().base;
  cu->write_vgpr(vb + 0, 0, pack16(util::f32_to_f16(1.0f), util::f32_to_f16(2.0f)));
  cu->write_vgpr(vb + 1, 0, pack16(util::f32_to_f16(3.0f), util::f32_to_f16(4.0f)));
  cu->write_vgpr(vb + 2, 0, std::bit_cast<uint32_t>(5.0f));

  const auto words = encode_vop2(/*op=*/2, /*vdst=*/2, /*src0=*/256, /*vsrc1=*/1);
  std::unique_ptr<Instruction> inst(decoder->decode(words.data()));
  ASSERT_NE(inst, nullptr);
  ASSERT_EQ(std::string_view(inst->mnemonic()), "v_dot2acc_f32_f16_e32");
  cu->execute_instruction(inst.get(), *wf);

  EXPECT_EQ(cu->read_vgpr(vb + 2, 0), std::bit_cast<uint32_t>(16.0f));

  cu->reset_all_wf();
}

TEST(Rdna4Dot2True16ExecutionTest, F16AppliesVop3ModifiersAndSelectedHalves) {
  amdgpu::GpuMemory gpu_mem("rdna4_dot2_true16_f16_mem");
  amdgpu::L2Cache l2("rdna4_dot2_true16_f16_l2");

  amdgpu::ComputeUnitCore::Config cfg{};
  cfg.arch = ROCJITSU_CODE_ARCH_RDNA4;
  cfg.num_wf_slots = 1;
  cfg.sgprs_per_wf = 106;
  cfg.vgprs_per_wf = 256;
  cfg.lds_size_kb = 64;

  auto cu = amdgpu::ComputeUnitCore::create("rdna4", cfg, &gpu_mem, &l2);
  ASSERT_NE(cu, nullptr);

  auto decoder = Decoder::create(ROCJITSU_CODE_ARCH_RDNA4);
  ASSERT_NE(decoder, nullptr);

  auto *wf = cu->dispatch_wf(0, 0, cfg.sgprs_per_wf, cfg.vgprs_per_wf);
  ASSERT_NE(wf, nullptr);
  wf->set_exec(0x1u);

  const uint32_t vb = wf->vgpr_alloc().base;
  cu->write_vgpr(vb + 0, 0, pack16(util::f32_to_f16(-2.0f), util::f32_to_f16(3.0f)));
  cu->write_vgpr(vb + 1, 0, pack16(util::f32_to_f16(-4.0f), util::f32_to_f16(-5.0f)));
  cu->write_vgpr(vb + 2, 0, pack16(util::f32_to_f16(0.25f), util::f32_to_f16(0.5f)));
  cu->write_vgpr(vb + 3, 0, 0xCAFEBEEFu);

  const auto words = encode_vop3(/*op=*/0x266, /*vdst=*/3, /*src0=*/256, /*src1=*/257,
                                 /*src2=*/258, /*abs=*/0x1, /*opsel=*/0xCu, /*clamp=*/1,
                                 /*omod=*/3, /*neg=*/0x2);
  std::unique_ptr<Instruction> inst(decoder->decode(words.data()));
  ASSERT_NE(inst, nullptr);
  ASSERT_EQ(std::string_view(inst->mnemonic()), "v_dot2_f16_f16");
  cu->execute_instruction(inst.get(), *wf);

  EXPECT_EQ(cu->read_vgpr(vb + 3, 0), pack16(0xBEEFu, util::f32_to_f16(1.0f)));

  cu->reset_all_wf();
}

TEST(Rdna4Dot2True16ExecutionTest, Bf16UsesSelectedAccumulatorAndDestinationHalf) {
  amdgpu::GpuMemory gpu_mem("rdna4_dot2_true16_bf16_mem");
  amdgpu::L2Cache l2("rdna4_dot2_true16_bf16_l2");

  amdgpu::ComputeUnitCore::Config cfg{};
  cfg.arch = ROCJITSU_CODE_ARCH_RDNA4;
  cfg.num_wf_slots = 1;
  cfg.sgprs_per_wf = 106;
  cfg.vgprs_per_wf = 256;
  cfg.lds_size_kb = 64;

  auto cu = amdgpu::ComputeUnitCore::create("rdna4", cfg, &gpu_mem, &l2);
  ASSERT_NE(cu, nullptr);

  auto decoder = Decoder::create(ROCJITSU_CODE_ARCH_RDNA4);
  ASSERT_NE(decoder, nullptr);

  auto *wf = cu->dispatch_wf(0, 0, cfg.sgprs_per_wf, cfg.vgprs_per_wf);
  ASSERT_NE(wf, nullptr);
  wf->set_exec(0x1u);

  const uint32_t vb = wf->vgpr_alloc().base;
  cu->write_vgpr(vb + 0, 0, pack16(util::f32_to_bf16(1.0f), util::f32_to_bf16(2.0f)));
  cu->write_vgpr(vb + 1, 0, pack16(util::f32_to_bf16(3.0f), util::f32_to_bf16(4.0f)));
  cu->write_vgpr(vb + 2, 0, pack16(util::f32_to_bf16(0.5f), util::f32_to_bf16(5.0f)));
  cu->write_vgpr(vb + 3, 0, 0xCAFEBEEFu);

  const auto words = encode_vop3(/*op=*/0x267, /*vdst=*/3, /*src0=*/256, /*src1=*/257,
                                 /*src2=*/258, /*abs=*/0, /*opsel=*/0x4u);
  std::unique_ptr<Instruction> inst(decoder->decode(words.data()));
  ASSERT_NE(inst, nullptr);
  ASSERT_EQ(std::string_view(inst->mnemonic()), "v_dot2_bf16_bf16");
  cu->execute_instruction(inst.get(), *wf);

  EXPECT_EQ(cu->read_vgpr(vb + 3, 0), pack16(util::f32_to_bf16(16.0f), 0xCAFEu));

  cu->reset_all_wf();
}

uint32_t wmma64_ab_lane(uint32_t row_or_col, uint32_t k) {
  return row_or_col + 16u * ((k >> 2) & 1u);
}

uint32_t wmma64_ab_index(uint32_t k) {
  const uint32_t reg =
      ((k >> 1) & 1u) + 2u * ((k >> 3) & 1u) + 4u * ((k >> 4) & 1u) + 8u * ((k >> 5) & 1u);
  return 2u * reg + (k & 1u);
}

void write_packed_byte(amdgpu::ComputeUnitCore &cu, uint32_t reg, uint32_t lane, uint32_t byte,
                       uint8_t value) {
  const uint32_t shift = 8u * byte;
  const uint32_t old = cu.read_vgpr(reg, lane);
  cu.write_vgpr(reg, lane, (old & ~(0xFFu << shift)) | (static_cast<uint32_t>(value) << shift));
}

void write_packed_half(amdgpu::ComputeUnitCore &cu, uint32_t reg, uint32_t lane, uint32_t half,
                       uint16_t value) {
  const uint32_t shift = 16u * half;
  const uint32_t old = cu.read_vgpr(reg, lane);
  cu.write_vgpr(reg, lane, (old & ~(0xFFFFu << shift)) | (static_cast<uint32_t>(value) << shift));
}

struct ForceScalarGuard {
  explicit ForceScalarGuard(bool force_scalar) : old_force_scalar(util::force_scalar()) {
    util::set_force_scalar_for_testing(force_scalar);
  }
  ~ForceScalarGuard() { util::set_force_scalar_for_testing(old_force_scalar); }

  bool old_force_scalar;
};

float wmma_test_a(uint32_t row, uint32_t k) {
  return static_cast<float>(static_cast<int>((row + k) % 5u) - 2);
}

float wmma_test_b(uint32_t k, uint32_t col) {
  return static_cast<float>(static_cast<int>((col + 3u * k) % 5u) - 2);
}

float wmma_test_c(uint32_t row, uint32_t col) {
  return static_cast<float>(static_cast<int>((2u * row + col) % 7u) - 3);
}

TEST(Gfx1250WmmaTest, F16Fp8K64MatchesReferenceLayout) {
  amdgpu::GpuMemory gpu_mem("gfx1250_wmma_f16_fp8_k64_mem");
  amdgpu::L2Cache l2("gfx1250_wmma_f16_fp8_k64_l2");

  amdgpu::ComputeUnitCore::Config cfg{};
  cfg.arch = ROCJITSU_CODE_ARCH_GFX1250;
  cfg.num_wf_slots = 1;
  cfg.sgprs_per_wf = 106;
  cfg.vgprs_per_wf = 256;
  cfg.lds_size_kb = 64;

  auto cu = amdgpu::ComputeUnitCore::create("gfx1250", cfg, &gpu_mem, &l2);
  ASSERT_NE(cu, nullptr);

  auto *wf = cu->dispatch_wf(0, 0, cfg.sgprs_per_wf, cfg.vgprs_per_wf);
  ASSERT_NE(wf, nullptr);
  ASSERT_EQ(wf->wf_size(), 32u);
  wf->set_exec((1ULL << wf->wf_size()) - 1ULL);

  auto decoder = Decoder::create(ROCJITSU_CODE_ARCH_GFX1250);
  ASSERT_NE(decoder, nullptr);

  const uint32_t vb = wf->vgpr_alloc().base;
  const uint32_t a_base = vb + 10;
  const uint32_t b_base = vb + 20;
  const uint32_t c_base = vb + 30;
  const uint32_t d_base = vb + 40;

  for (uint32_t reg = 0; reg < 8; ++reg) {
    for (uint32_t lane = 0; lane < wf->wf_size(); ++lane) {
      cu->write_vgpr(a_base + reg, lane, 0);
      cu->write_vgpr(b_base + reg, lane, 0);
    }
  }
  for (uint32_t reg = 0; reg < 4; ++reg) {
    for (uint32_t lane = 0; lane < wf->wf_size(); ++lane) {
      cu->write_vgpr(c_base + reg, lane, 0);
      cu->write_vgpr(d_base + reg, lane, 0xDEADBEEFu);
    }
  }

  for (uint32_t row = 0; row < 16; ++row) {
    for (uint32_t k = 0; k < 64; ++k) {
      const uint32_t idx = wmma64_ab_index(k);
      write_packed_byte(*cu, a_base + idx / 4u, wmma64_ab_lane(row, k), idx % 4u,
                        util::f32_to_fp8_e4m3_rne(wmma_test_a(row, k)));
    }
  }
  for (uint32_t k = 0; k < 64; ++k) {
    for (uint32_t col = 0; col < 16; ++col) {
      const uint32_t idx = wmma64_ab_index(k);
      write_packed_byte(*cu, b_base + idx / 4u, wmma64_ab_lane(col, k), idx % 4u,
                        util::f32_to_fp8_e4m3_rne(wmma_test_b(k, col)));
    }
  }
  for (uint32_t row = 0; row < 16; ++row) {
    for (uint32_t col = 0; col < 16; ++col) {
      const auto out = amdgpu::wmma_output_loc_16(16, 16, row, col);
      write_packed_half(*cu, c_base + out.reg, out.lane, out.sub_element,
                        util::f32_to_f16(wmma_test_c(row, col)));
    }
  }

  amdgpu::exec_wmma_f16(*cu, 16, 16, 64, 8, d_base, a_base, b_base, c_base, amdgpu::extract_fp8,
                        amdgpu::extract_fp8, amdgpu::ACC_FROM_VGPR);

  auto expect_reference = [&] {
    for (uint32_t row = 0; row < 16; ++row) {
      for (uint32_t col = 0; col < 16; ++col) {
        float ref = wmma_test_c(row, col);
        for (uint32_t k = 0; k < 64; ++k)
          ref += wmma_test_a(row, k) * wmma_test_b(k, col);
        const auto out = amdgpu::wmma_output_loc_16(16, 16, row, col);
        const uint32_t raw = cu->read_vgpr(d_base + out.reg, out.lane);
        const auto actual = static_cast<uint16_t>((raw >> (16u * out.sub_element)) & 0xFFFFu);
        EXPECT_EQ(actual, util::f32_to_f16(ref)) << "row=" << row << " col=" << col;
      }
    }
  };
  expect_reference();

  for (uint32_t reg = 0; reg < 4; ++reg)
    for (uint32_t lane = 0; lane < wf->wf_size(); ++lane)
      cu->write_vgpr(d_base + reg, lane, 0xDEADBEEFu);

  const uint32_t wmma_words[] = {
      0xCC6E0000U | 40u,
      (256u + 10u) | ((256u + 20u) << 9u) | ((256u + 30u) << 18u),
  };
  std::unique_ptr<Instruction> inst(decoder->decode(wmma_words));
  ASSERT_NE(inst, nullptr);
  ASSERT_EQ(std::string_view(inst->mnemonic()), "v_wmma_f16_16x16x64_fp8_fp8");
  cu->execute_instruction(inst.get(), *wf);
  expect_reference();

  cu->reset_all_wf();
}

TEST(Gfx1250WmmaTest, CModifierAppliesAbsBeforeNegate) {
  EXPECT_EQ(amdgpu::wmma_c_modifier(0u, 0u), 0u);
  EXPECT_EQ(amdgpu::wmma_c_modifier(1u << 2u, 0u), 1u);
  EXPECT_EQ(amdgpu::wmma_c_modifier(0u, 1u << 2u), 2u);
  EXPECT_EQ(amdgpu::wmma_c_modifier(1u << 2u, 1u << 2u), 3u);

  EXPECT_EQ(amdgpu::apply_wmma_c_modifier(-3.0f, 0u), -3.0f);
  EXPECT_EQ(amdgpu::apply_wmma_c_modifier(-3.0f, 1u), 3.0f);
  EXPECT_EQ(amdgpu::apply_wmma_c_modifier(-3.0f, 2u), 3.0f);
  EXPECT_EQ(amdgpu::apply_wmma_c_modifier(-3.0f, 3u), -3.0f);
}

