TEST(Gfx1250ExecMaskTest, Vop3CmpF32PreservesHighMaskSgprOnWave32) {
  amdgpu::GpuMemory gpu_mem("gfx1250_cmp_f32_mask_mem");
  amdgpu::L2Cache l2("gfx1250_cmp_f32_mask_l2");

  amdgpu::ComputeUnitCore::Config cfg{};
  cfg.arch = ROCJITSU_CODE_ARCH_GFX1250;
  cfg.num_wf_slots = 1;
  cfg.sgprs_per_wf = 106;
  cfg.vgprs_per_wf = 256;
  cfg.lds_size_kb = 64;

  auto cu = amdgpu::ComputeUnitCore::create("gfx1250", cfg, &gpu_mem, &l2);
  ASSERT_NE(cu, nullptr);

  auto decoder = Decoder::create(ROCJITSU_CODE_ARCH_GFX1250);
  ASSERT_NE(decoder, nullptr);

  auto *wf = cu->dispatch_wf(0, 0, cfg.sgprs_per_wf, cfg.vgprs_per_wf);
  ASSERT_NE(wf, nullptr);
  ASSERT_EQ(wf->wf_size(), 32u);
  const uint64_t all_lanes = (1ULL << wf->wf_size()) - 1ULL;
  wf->set_exec(all_lanes);

  constexpr uint32_t saved_exec = 0xDEADBEEFu;
  cu->write_sgpr(wf->sgpr_alloc().base + 1, saved_exec);

  const uint32_t v4 = wf->vgpr_alloc().base + 4;
  for (uint32_t lane = 0; lane < wf->wf_size(); ++lane) {
    const float value = lane == 4 ? 0.0f : 1.0f;
    cu->write_vgpr(v4, lane, std::bit_cast<uint32_t>(value));
  }

  // v_cmp_eq_f32_e64 s0, 0, v4
  const uint32_t compare_words[] = {0xD4120000U, 0x02020880U};
  std::unique_ptr<Instruction> compare(decoder->decode(compare_words));
  ASSERT_NE(compare, nullptr);
  ASSERT_EQ(std::string_view(compare->mnemonic()), "v_cmp_eq_f32");
  cu->execute_instruction(compare.get(), *wf);

  EXPECT_EQ(cu->read_sgpr(wf->sgpr_alloc().base + 0), 1u << 4);
  EXPECT_EQ(cu->read_sgpr(wf->sgpr_alloc().base + 1), saved_exec);

  cu->reset_all_wf();
}

